<span class="line"><span style="color:#89DDFF;">&gt;&gt;&gt;</span><span style="color:#BABED8;"> </span><span style="color:#82AAFF;">tensor</span><span style="color:#89DDFF;">([</span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">.,</span><span style="color:#82AAFF;"> </span><span style="color:#F78C6C;">1</span><span style="color:#89DDFF;">.,</span><span style="color:#82AAFF;"> </span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">.,</span><span style="color:#82AAFF;"> </span><span style="color:#F78C6C;">1</span><span style="color:#89DDFF;">.,</span><span style="color:#82AAFF;"> </span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">.])</span></span>
