<span class="line"><span style="color:#BABED8;">spikegen</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">delta</span><span style="color:#89DDFF;">(</span><span style="color:#82AAFF;">b</span><span style="color:#89DDFF;">,</span><span style="color:#82AAFF;"> </span><span style="color:#BABED8;font-style:italic;">threshold</span><span style="color:#89DDFF;">=</span><span style="color:#F78C6C;">1</span><span style="color:#89DDFF;">,</span><span style="color:#82AAFF;"> </span><span style="color:#BABED8;font-style:italic;">off_spike</span><span style="color:#89DDFF;">=True)</span></span>
